[leetcode-349. 两个数组的交集](https://leetcode.cn/problems/intersection-of-two-arrays/)
```C++
class Solution {
public:
    vector<int> intersection(vector<int>& nums1, vector<int>& nums2) {
        unordered_set<int> result_set; // 存放结果，之所以用set是为了给结果集去重
        unordered_set<int> nums_set(nums1.begin(), nums1.end()); //两个迭代器复制元素
        for (int num : nums2) {
            // 发现nums2的元素 在nums_set里又出现过
            if (nums_set.find(num) != nums_set.end()) {
                result_set.insert(num);
            }
        }
        return vector<int>(result_set.begin(), result_set.end());
    }
};
```

# [142. 环形链表 II](https://leetcode.cn/problems/linked-list-cycle-ii/description/)

这道题非常地有趣，旨在找到链表中环的起始点。

## 哈希法

最容易的办法是遍历链表中的每个节点，用哈希表储存地址，如果有重复的内容，说明找到了环的起始点。

```C++
class Solution {
public:
    ListNode *detectCycle(ListNode *head) {
        unordered_set<ListNode *> visited;
        while(head != nullptr)
        {
            if(visited.count(head)) //返回head出现的次数
            {
                return head;
            }
            visited.insert(head);
            head = head->next;
        }
        return nullptr;
        }
};

```

## 数学法
第二种办法是数学法，具体可以参考题解：[环形链表 II（双指针法，清晰图解）](https://leetcode.cn/problems/linked-list-cycle-ii/solutions/12616/linked-list-cycle-ii-kuai-man-zhi-zhen-shuang-zhi-/)

概括一下：

根据：

f=2s （快指针每次2步，路程刚好2倍）

f = s + nb (相遇时，刚好多走了n圈）

推出：s = nb

从head结点走到入环点需要走 ： a + nb， 而slow已经走了nb，那么slow再走a步就是入环点了。

如何知道slow刚好走了a步？ 从head开始，和slow指针一起走，相遇时刚好就是a步.

```C++
class Solution {
public:
    ListNode *detectCycle(ListNode *head) {
         ListNode* fast = head;
         ListNode* slow = head;
        while (true) {
            if (fast == NULL || fast->next == NULL) return NULL;
            fast = fast->next->next;
            slow = slow->next;
            if (fast == slow) break;
        }
        fast = head;
        while (slow != fast) {
            slow = slow->next;
            fast = fast->next;
        }
        return fast;
    }
};
```

## 巧妙法

O(n)算法，应该是最快的。 堆的地址从低到高，LeetCode的链表内存是顺序申请的，如果有环，head->next一定小于或等于head。

这个办法在实际生产中没法使用，因为堆内会不断地new和delete新的节点。

```C++
class Solution {
public:
    ListNode *detectCycle(ListNode *head) {
        while(head) {
            if(!less<ListNode *>()(head, head->next)) {
                return head->next;
            }
            head = head->next;
        }
        return nullptr;
    }
};
```

# [160. 相交链表](https://leetcode.cn/problems/intersection-of-two-linked-lists/)

由于链表的特殊性质，一旦多条链表在一个节点相交，那么后面所有的节点都是重合的。所以，链表相交一定发生在链表的尾部。

解决方案是，把两条链表尾部对齐，使两指针一起移动，如果发现地址相同，说明链表已经相交。

```C++
class Solution {
public:
    ListNode *getIntersectionNode(ListNode *headA, ListNode *headB) {
        ListNode* curA = headA;
        ListNode* curB = headB;
        int lenA = 0, lenB = 0;
        while (curA != NULL) { // 求链表A的长度
            lenA++;
            curA = curA->next;
        }
        while (curB != NULL) { // 求链表B的长度
            lenB++;
            curB = curB->next;
        }
        curA = headA;
        curB = headB;
        // 让curA为最长链表的头，lenA为其长度
        if (lenB > lenA) {
            swap (lenA, lenB);
            swap (curA, curB);
        }
        // 求长度差
        int gap = lenA - lenB;
        // 让curA和curB在同一起点上（末尾位置对齐）
        while (gap--) {
            curA = curA->next;
        }
        // 遍历curA 和 curB，遇到相同则直接返回
        while (curA != NULL) {
            if (curA == curB) {
                return curA;
            }
            curA = curA->next;
            curB = curB->next;
        }
        return NULL;
    }
};
```

# [19. 删除链表的倒数第 N 个结点](https://leetcode.cn/problems/remove-nth-node-from-end-of-list/)

熟悉的双指针，让fastIndex先前进n步，再让两个指针一起前进，直到fastIndex到达最后一个元素。此时，slowIndex所在的位置即为要删除节点的前一个元素，方便删除操作。

本题稍微卡壳的地方在于，要删除的节点是第一个节点的问题，是没法找到要删除的节点的前一个节点的。但是在引入虚拟头节点dummyHead后，问题就解决了。

```C++
class Solution {
public:
    ListNode* removeNthFromEnd(ListNode* head, int n) {
        ListNode* dummyHead = new ListNode(0);
        dummyHead->next = head;
        ListNode* slowIndex = dummyHead;
        ListNode* fastIndex = dummyHead;
        for(int i = 0; i < n; i++)
        {
            fastIndex = fastIndex->next;
        }

        while(fastIndex->next != NULL)
        {
            fastIndex = fastIndex->next;
            slowIndex = slowIndex->next;
        }

        ListNode* temp = slowIndex->next;
        slowIndex->next = temp->next;
        delete temp; 

        return dummyHead->next;
    }
};
```

# [66. 加一](https://leetcode.cn/problems/plus-one/description/)
```C++
class Solution {
public:
    vector<int> plusOne(vector<int>& digits) {
        for(int i = digits.size() - 1; i >= 0; i--)
        {
            if(digits[i] != 9)
            {
                digits[i]++;
                return digits;
            }
            else
            digits[i] = 0;
        }
        //出了循环，说明全是9
        vector<int> result(digits.size() + 1, 0);
        result[0] = 1;
        return result;
    }
};
```

# [leetcode-206. 反转链表](https://leetcode.cn/problems/reverse-linked-list/)

灵活运用了双指针，一快一慢两个指针

![翻转链表](https://picx.zhimg.com/80/v2-1032cc15783f29d404801aaad96a0e4e_720w.webp?source=d16d100b)
```C++
class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        ListNode* pre = NULL;
        ListNode* cur = head;
        ListNode* temp; //用临时节点储存cur的下个节点。
        while(cur != NULL)
        {
            temp = cur->next;
            cur->next = pre;
            pre = cur;
            cur = temp;
        }
        return pre;
    }
};
```

# [leetcode-707. 设计链表](https://leetcode.cn/problems/design-linked-list/)
```C++
class MyLinkedList {
public:
    // 定义链表节点结构体
    struct LinkedNode {
        int val;
        LinkedNode* next;
        LinkedNode(int val):val(val), next(nullptr){}
    };

    // 初始化链表
    MyLinkedList() {
        _dummyHead = new LinkedNode(0); // 这里定义的头结点 是一个虚拟头结点，而不是真正的链表头结点
        _size = 0;
    }

    // 获取到第index个节点数值，如果index是非法数值直接返回-1， 注意index是从0开始的，第0个节点就是头结点
    int get(int index) {
        if (index > (_size - 1) || index < 0) {
            return -1;
        }
        LinkedNode* cur = _dummyHead->next;
        while(index--){ // 如果--index 就会陷入死循环
            cur = cur->next;
        }
        return cur->val;
    }

    // 在链表最前面插入一个节点，插入完成后，新插入的节点为链表的新的头结点
    void addAtHead(int val) {
        LinkedNode* newNode = new LinkedNode(val);
        newNode->next = _dummyHead->next;
        _dummyHead->next = newNode;
        _size++;
    }

    // 在链表最后面添加一个节点
    void addAtTail(int val) {
        LinkedNode* newNode = new LinkedNode(val);
        LinkedNode* cur = _dummyHead;
        while(cur->next != nullptr){
            cur = cur->next;
        }
        cur->next = newNode;
        _size++;
    }

    // 在第index个节点之前插入一个新节点，例如index为0，那么新插入的节点为链表的新头节点。
    // 如果index 等于链表的长度，则说明是新插入的节点为链表的尾结点
    // 如果index大于链表的长度，则返回空
    void addAtIndex(int index, int val) {
        if (index > _size) {
            return;
        }
        LinkedNode* newNode = new LinkedNode(val);
        LinkedNode* cur = _dummyHead;
        while(index--) {
            cur = cur->next;
        }
        newNode->next = cur->next;
        cur->next = newNode;
        _size++;
    }

    // 删除第index个节点，如果index 大于等于链表的长度，直接return，注意index是从0开始的
    void deleteAtIndex(int index) {
        if (index >= _size || index < 0) {
            return;
        }
        LinkedNode* cur = _dummyHead;
        while(index--) {
            cur = cur ->next;
        }
        LinkedNode* tmp = cur->next;
        cur->next = cur->next->next;
        delete tmp;
        _size--;
    }

    // 打印链表
    void printLinkedList() {
        LinkedNode* cur = _dummyHead;
        while (cur->next != nullptr) {
            cout << cur->next->val << " ";
            cur = cur->next;
        }
        cout << endl;
    }
private:
    int _size;
    LinkedNode* _dummyHead;

};
```

# [203. 移除链表元素](https://leetcode.cn/problems/remove-linked-list-elements/)

链表的种种性质操作早已熟记于心，但是上手写代码的时候还是有种种困难。
话不多说，直接上代码：
```C++
class Solution {
public:
    ListNode* removeElements(ListNode* head, int val) {
        ListNode* dummyHead = new ListNode(0,head);  //创建虚拟头结点，后面操作可以统一
        ListNode* cur = dummyHead; //创建用来遍历的节点，cur=current
        while (cur->next != NULL)
        {
            if(cur->next->val == val)
            {
                ListNode* temp = cur->next;
                cur->next = cur->next->next; //删除操作，反而是最简单的一步
                delete temp; //C++一定要释放空间
            }
            else
            {
                cur = cur->next; //不是要删除的节点，就跳过
            }
        }
        head = dummyHead->next;
        delete dummyHead;//释放空间
        return head;
    }
};
```

# [leetcode-59. 螺旋矩阵II](https://leetcode.cn/problems/spiral-matrix-ii/)

以n=3为例，此矩阵共赋值9次，移动8次，沿4个方向移动，问题的关键在于如何把这些操作不重不漏地分类完成。

下一步要思考的是，根据n的不同，如何把这些操作分配到不同的轮次内，一个可行的办法是转一圈，算作一个轮次。

一个轮次内有4个方向，由此可知，至少要写4个循环才能完成目标，同一方向的操作，写在一个循环内。

最后，在完成一圈后，移动到下一圈开始的位置，即可完成循环。

![实例](https://assets.leetcode.com/uploads/2020/11/13/spiraln.jpg)

```C++
class Solution {
public:
    vector<vector<int>> generateMatrix(int n) {
        vector<vector<int>> result(n,vector(n,0));
        int i = 1, x = 0, y = 0, loop = n;  //loop为轮次的长度
        while (loop > 0)
        {
            for(int step = 0; step < loop -1; step++)
            {
                result[x][y] = i;
                y++;
                i++;
            }
            for(int step = 0; step < loop - 1; step++)
            {
                result[x][y] = i;
                x++;
                i++;
            }
            for(int step = 0; step < loop - 1; step++)
            {
                result[x][y] = i;
                y--;
                i++;
            }
            for(int step = 0; step < loop - 2; step++)
            {
                result[x][y] = i;
                x--;
                i++;
            }
            //四次循环，对应四个方向的移动
            result[x][y] = i;
            y++;
            i++;
            //把位置重置到下一轮的起始点
            loop -= 2;
        }
        return result;
    }
};
```

# [leetcode-209. 长度最小的子数组](https://leetcode.cn/problems/minimum-size-subarray-sum/description/)

如果使用暴力解法，需要用两个for循环嵌套，时间复杂度很明显是O(n^2)。

巧妙的方法是使用滑动窗口的方法，类似计算机网络中的内容，窗口由一前一后两个指针约束。窗口的前指针在循环中不停地前进，寻找最优解。当窗口中的内容不符合最优解的时候，移动后指针直到重新符合条件，再进入循环。

这样做的好处是，通过操作两个指针，只进行了一次循环，时间复杂度降低为O(n).
```C++
    //经验不足导致的代码又臭又长
    class Solution {
    public:
        int minSubArrayLen(int target, vector<int>& nums) {
            int sum = nums[0], fastIndex = 0, slowIndex = 0, length = 1, minLength = nums.size() + 1;
            if(sum >= target)
            {
                return 1;
            }
            while(fastIndex < nums.size() - 1)
            {
            fastIndex++;
            length++;
            sum += nums[fastIndex];
            while(sum - nums[slowIndex] >= target)
            {
                sum -= nums[slowIndex];
                slowIndex++;
                length --;
            }
            if(sum >= target)
            minLength = (length < minLength)? length : minLength;
            }
            if(minLength == nums.size() + 1)
            {
                return 0;
            }
            return minLength;  
        }
    };
```
